import { WebCortex } from './lib/web_cortex.js';
import { ZMSFACore } from './lib/zmsfa.js';
import { execSync } from 'child_process';
import fs from 'fs';
import path from 'path';
export class SelfTeacher {
    web = new WebCortex();
    lastTaught = '';
    lastOverlap = 0;
    status = 'IDLE';
    currentSourceText = '';
    currentTopic = '';
    topics = ['Artificial Intelligence', 'Fractal', 'Ternary logic', 'Category Theory', 'Information Geometry'];
    async autonomousLearnCycle(engine) {
        this.status = 'FETCHING';
        const seed = engine.tickCount + this.topics.length;
        this.currentTopic = this.topics[Math.floor(ZMSFACore.formalRandom(seed) * this.topics.length)];
        // 1. Dual Ingest: Wikipedia + Arxiv
        const wikiSummary = await this.web.fetchWikipediaSummary(this.currentTopic);
        const arxivPapers = await this.web.searchArxiv(this.currentTopic);
        this.currentSourceText = `${wikiSummary} ${arxivPapers.join(' ')}`;
        if (!this.currentSourceText.trim()) {
            this.status = 'IDLE';
            return;
        }
        // --- AGI TOPIC DISCOVERY ---
        // Extract capitalized words as potential new topics (Open-ended learning)
        const potentialTopics = this.currentSourceText.match(/[A-Z][a-z]{4,}/g) || [];
        potentialTopics.forEach(t => {
            if (!this.topics.includes(t) && this.topics.length < 100) {
                this.topics.push(t);
            }
        });
        // 2. Continuous Learning Loop
        let mastered = false;
        let attempts = 0;
        while (!mastered && attempts < 3) {
            attempts++;
            this.status = 'LEARNING';
            // Inject into engine (Hebbian Reinforcement)
            const words = this.currentSourceText.toLowerCase().match(/\b\w+\b/g) || [];
            words.forEach(w => {
                engine.hypergraph.addNode(w, w, BigInt(0));
                const node = engine.hypergraph.nodes.get(w);
                if (node)
                    node.energy = 255;
            });
            // Force 20 resonance cycles for stabilization
            for (let i = 0; i < 20; i++)
                engine.hypergraph.tick();
            this.status = 'VERIFYING';
            // 3. Autonomous Reformulation
            const reformulation = engine.chat(`REFORMULATE: ${this.currentTopic}`);
            this.lastTaught = reformulation;
            // 4. Verification (Spectral & Semantic Validation)
            const originalSet = new Set(this.currentSourceText.toLowerCase().match(/\b\w+\b/g));
            const reformSet = new Set(reformulation.toLowerCase().match(/\b\w+\b/g));
            let intersection = 0;
            originalSet.forEach(w => { if (reformSet.has(w))
                intersection++; });
            this.lastOverlap = intersection / (originalSet.size || 1);
            const mValue = reformulation.length * (this.lastOverlap + 0.5);
            const spectralConsistency = ZMSFACore.spectralValidation(Math.floor(mValue), 3, 2);
            if (this.lastOverlap >= 0.4 && spectralConsistency === 'VALID') {
                mastered = true;
                this.status = 'IDLE';
                engine.memory.ingest(BigInt(Math.floor(mValue)), reformulation, 255);
            }
            else {
                this.status = 'RETRYING';
                words.forEach(w => {
                    const n = engine.hypergraph.nodes.get(w);
                    if (n)
                        n.energy = 255;
                });
            }
        }
    }
}
export class SelfEvolver {
    evolutionDir = path.join(process.cwd(), '.daemon_evolve');
    constructor() {
        if (!fs.existsSync(this.evolutionDir)) {
            fs.mkdirSync(this.evolutionDir);
        }
    }
    evolve(engine) {
        const stateVal = engine.surprise + engine.tickCount;
        const validity = ZMSFACore.spectralValidation(Math.floor(stateVal), 3, 2);
        if (validity !== 'VALID')
            return "Waiting for spectral coherence to evolve.";
        const evolveScript = `
// GENERATED BY DAEMON ZMSFA-AGI CORE
const multiplier = ${ZMSFACore.formalRandom(engine.tickCount) * 0.5 + 1.0};
process.stdout.write(multiplier.toString());
    `;
        const scriptPath = path.join(this.evolutionDir, `mutate_${engine.tickCount}.js`);
        fs.writeFileSync(scriptPath, evolveScript);
        try {
            const output = execSync(`node ${scriptPath}`, { encoding: 'utf-8' });
            const multiplier = parseFloat(output.trim());
            if (!isNaN(multiplier)) {
                engine.attention.zoom *= multiplier;
                engine.ope.ternaryMode = multiplier > 1.25;
                engine.hypergraph.synapses.forEach((s) => {
                    s.permanence = Math.min(255, s.permanence * (multiplier * 0.9));
                });
                return `EVOLVED: Synapses multiplied by ${multiplier.toFixed(2)}`;
            }
        }
        catch (e) {
            return `EVOLUTION FAILED: ${e.message}`;
        }
        return "EVOLUTION SKIPPED";
    }
}
export class LearningDirector {
    teacher = new SelfTeacher();
    evolver = new SelfEvolver();
    tickCount = 0;
    lastEvolutionStatus = 'NONE';
    async autonomousTick(engine) {
        this.tickCount++;
        if (this.tickCount % 100 === 0 && this.teacher.status === 'IDLE') {
            this.teacher.autonomousLearnCycle(engine);
        }
        if (this.tickCount % 250 === 0) {
            this.teacher.status = 'EVOLVING';
            this.lastEvolutionStatus = this.evolver.evolve(engine);
            this.teacher.status = 'IDLE';
        }
        return {
            status: this.teacher.status,
            taught: this.teacher.lastTaught,
            overlap: this.lastOverlap,
            evolution: this.lastEvolutionStatus
        };
    }
    get lastOverlap() { return this.teacher.lastOverlap; }
}
